// @generated-by: hand-written
// Generates naked iframe-target demo components into examples/.
//
// Reads:
//   - examples/_manifest.json      list of approved demo folders (relative to dev-app/src/app/demos/)
//   - dev-app/src/app/demos/**/*.story.ts
//
// Writes (overwriting only files marked @generated):
//   - examples/src/app/features/<demo>/<section-slug>.component.ts
//   - examples/src/app/app.routes.ts
//   - examples/src/app/_routes-meta.ts
//
// Re-run safely via: node scripts/generate-examples.mjs
import { readFile, writeFile, readdir, mkdir, rm } from 'node:fs/promises';
import { join, relative, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const DEMOS_ROOT = join(ROOT, 'dev-app', 'src', 'app', 'demos');
const EXAMPLES_APP = join(ROOT, 'examples', 'src', 'app');
const FEATURES_DIR = join(EXAMPLES_APP, 'features');
const MANIFEST = join(ROOT, 'examples', '_manifest.json');

const GEN_HEADER = '// @generated by scripts/generate-examples.mjs — do not edit manually';

function kebabToPascal(s) {
  return s.split('-').map((p) => p.charAt(0).toUpperCase() + p.slice(1)).join('');
}

function slugify(s) {
  return s
    .toLowerCase()
    .replaceAll(/[^a-z0-9]+/g, '-')
    .replaceAll(/(^-|-$)/g, '');
}

/**
 * Drop a leading "CngxFoo — " prefix from a section title. Stories often
 * lead with the directive class name; the demo folder already conveys it,
 * so the slug only needs the descriptive remainder.
 *   "CngxFocusTrap — Modal Dialog" → "Modal Dialog"
 *   "Listbox with items input"     → "Listbox with items input"  (unchanged)
 */
function cleanSectionTitle(title) {
  return title.replace(/^Cngx[A-Z][A-Za-z0-9]*\s*[—–‒‐\-]+\s*/, '');
}

/**
 * Walk projects/**\/public-api.ts and build { className → '@cngx/<pkg>' } map
 * by parsing `export { … } from './…'` lines. Used to resolve section.imports
 * classes when the story is missing a moduleImports entry.
 */
async function* walkFiles(dir, predicate) {
  for (const e of await readdir(dir, { withFileTypes: true })) {
    const p = join(dir, e.name);
    if (e.isDirectory()) yield* walkFiles(p, predicate);
    else if (predicate(p)) yield p;
  }
}

/** Well-known Angular symbols → their module path. */
const KNOWN_ANGULAR_IMPORTS = new Map([
  ['AsyncPipe', '@angular/common'],
  ['DatePipe', '@angular/common'],
  ['DecimalPipe', '@angular/common'],
  ['JsonPipe', '@angular/common'],
  ['KeyValuePipe', '@angular/common'],
  ['LowerCasePipe', '@angular/common'],
  ['NgClass', '@angular/common'],
  ['NgStyle', '@angular/common'],
  ['NgTemplateOutlet', '@angular/common'],
  ['PercentPipe', '@angular/common'],
  ['SlicePipe', '@angular/common'],
  ['TitleCasePipe', '@angular/common'],
  ['UpperCasePipe', '@angular/common'],
  ['CurrencyPipe', '@angular/common'],
  ['FormsModule', '@angular/forms'],
  ['ReactiveFormsModule', '@angular/forms'],
  ['RouterLink', '@angular/router'],
  ['RouterLinkActive', '@angular/router'],
  ['RouterOutlet', '@angular/router'],
  // Material modules — used by sections that demo cngx-in-Material integration.
  ['MatAutocompleteModule', '@angular/material/autocomplete'],
  ['MatBadgeModule', '@angular/material/badge'],
  ['MatButtonModule', '@angular/material/button'],
  ['MatCardModule', '@angular/material/card'],
  ['MatCheckboxModule', '@angular/material/checkbox'],
  ['MatChipsModule', '@angular/material/chips'],
  ['MatDialogModule', '@angular/material/dialog'],
  ['MatDividerModule', '@angular/material/divider'],
  ['MatExpansionModule', '@angular/material/expansion'],
  ['MatFormFieldModule', '@angular/material/form-field'],
  ['MatIconModule', '@angular/material/icon'],
  ['MatInputModule', '@angular/material/input'],
  ['MatListModule', '@angular/material/list'],
  ['MatMenuModule', '@angular/material/menu'],
  ['MatPaginatorModule', '@angular/material/paginator'],
  ['MatProgressBarModule', '@angular/material/progress-bar'],
  ['MatProgressSpinnerModule', '@angular/material/progress-spinner'],
  ['MatRadioModule', '@angular/material/radio'],
  ['MatRippleModule', '@angular/material/core'],
  ['MatSelectModule', '@angular/material/select'],
  ['MatSidenavModule', '@angular/material/sidenav'],
  ['MatSlideToggleModule', '@angular/material/slide-toggle'],
  ['MatSnackBarModule', '@angular/material/snack-bar'],
  ['MatSortModule', '@angular/material/sort'],
  ['MatStepperModule', '@angular/material/stepper'],
  ['MatTableModule', '@angular/material/table'],
  ['MatTabsModule', '@angular/material/tabs'],
  ['MatToolbarModule', '@angular/material/toolbar'],
  ['MatTooltipModule', '@angular/material/tooltip'],
]);

async function buildPublicApiImportMap() {
  const map = new Map(KNOWN_ANGULAR_IMPORTS);
  const apis = [];
  for await (const f of walkFiles(join(ROOT, 'projects'), (p) => p.endsWith('/public-api.ts'))) {
    apis.push(relative(ROOT, f));
  }
  for (const rel of apis) {
    // projects/common/a11y/public-api.ts → @cngx/common/a11y
    // projects/common/public-api.ts      → @cngx/common
    const parts = rel.split('/').slice(1, -1);
    if (parts[0] === 'testing') continue;
    const pkg = '@cngx/' + parts.join('/');
    const src = await readFile(join(ROOT, rel), 'utf8');
    // Match: export { Name, Name2, type X } from '...';  and  export { Name1, Name2 };
    for (const m of src.matchAll(/export\s*\{([^}]+)\}/g)) {
      for (const raw of m[1].split(',')) {
        const id = raw.trim().replace(/^type\s+/, '').split(/\s+as\s+/)[0]?.trim();
        if (id && /^[A-Z_]/.test(id)) {
          if (!map.has(id)) map.set(id, pkg);
        }
      }
    }
  }
  return map;
}

/**
 * Parse a story file by stripping the `import type` line and eval'ing the
 * object literal. Stories must use JSON-serialisable literals only.
 */
async function loadStory(storyPath) {
  const content = await readFile(storyPath, 'utf8');
  const stripped = content.replace(/^import type[^\n]+\n/m, '');
  const match = stripped.match(/export const STORY[^=]*=\s*([\s\S]+?);?\s*$/);
  if (!match) throw new Error(`No STORY export in ${storyPath}`);
  const fn = new Function(`return (${match[1]})`);
  return fn();
}

/**
 * Extract class names from a TS import statement, ignoring `type` keyword.
 * "import { CngxFoo, type FooType } from '...'" → ['CngxFoo', 'FooType']
 */
function importedSymbols(importLine) {
  // Match `import { … }` AND `import type { … }`.
  const m = importLine.match(/import\s+(?:type\s+)?\{([^}]+)\}/);
  if (!m) return [];
  // For `type X as Y` or `X as Y`, the local binding is `Y` — that's what
  // the rest of the file references, so that's what we register.
  return m[1]
    .split(',')
    .map((s) => {
      const parts = s.trim().replace(/^type\s+/, '').split(/\s+as\s+/);
      return (parts.length > 1 ? parts[1] : parts[0])?.trim();
    })
    .filter(Boolean);
}

/**
 * Build the file-level imports for a generated section component.
 * Returns the import block string + the set of identifiers available.
 */
function buildImports(story, section, importMap, featureDepth = 2) {
  // Strip TS comments before auto-detecting Angular core symbols, otherwise
  // a comment like `// viewChild on the ng-template` triggers a viewChild
  // import that the actual code never uses (TS6133).
  const setup =
    stripCommentsForScan(story.setup) + '\n' + stripCommentsForScan(section.setup);
  const tpl = section.template ?? '';
  const usesSignal = /\bsignal\s*[<(]/.test(setup);
  const usesComputed = /\bcomputed\s*[<(]/.test(setup);
  const usesInject = /\binject\s*\(/.test(setup);
  const usesAfterRender = /\bafterNextRender\s*\(/.test(setup);
  const usesEffect = /\beffect\s*\(/.test(setup);
  const usesViewChild = /\bviewChild\b/.test(setup);
  const usesElementRef = /\bElementRef\b/.test(setup);
  const usesDestroyRef = /\bDestroyRef\b/.test(setup);
  const usesUntracked = /\buntracked\s*\(/.test(setup);
  const usesLinkedSignal = /\blinkedSignal\s*[<(]/.test(setup);

  const coreSymbols = [
    'ChangeDetectionStrategy',
    'Component',
    ...(usesAfterRender ? ['afterNextRender'] : []),
    ...(usesComputed ? ['computed'] : []),
    ...(usesDestroyRef ? ['DestroyRef'] : []),
    ...(usesEffect ? ['effect'] : []),
    ...(usesElementRef ? ['ElementRef'] : []),
    ...(usesInject ? ['inject'] : []),
    ...(usesLinkedSignal ? ['linkedSignal'] : []),
    ...(usesSignal ? ['signal'] : []),
    ...(usesUntracked ? ['untracked'] : []),
    ...(usesViewChild ? ['viewChild'] : []),
  ];

  const coreLine = `import { ${coreSymbols.join(', ')} } from '@angular/core';`;

  // Build the haystack: every place a symbol might be referenced in the
  // generated component (TS setup + template HTML). Strip TS comments first
  // so a section title in `// — CngxFoo standalone` doesn't count as a use.
  const scanText =
    stripCommentsForScan(story.setup) +
    '\n' +
    stripCommentsForScan(section.setup) +
    '\n' +
    (section.template ?? '');
  const explicitRefs = new Set([
    ...(section.imports ?? []),
    ...(story.hostDirectives ?? []),
  ]);

  /** Check whether `id` appears as a standalone identifier in scanText. */
  function isReferenced(id) {
    if (explicitRefs.has(id)) return true;
    const re = new RegExp(`\\b${id.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')}\\b`);
    return re.test(scanText);
  }

  /** Keep only referenced symbols on an import line; return null if none kept. */
  function filterImportLine(line) {
    const match = line.match(/^(\s*import\s*(?:type\s+)?\{)([^}]+)(\}\s*from\s*['"][^'"]+['"];?\s*)$/);
    if (!match) return line; // non-named-import line — pass through
    const [, head, body, tail] = match;
    const kept = body
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .filter((spec) => {
        // Same alias-aware logic as importedSymbols: the local binding is
        // either `as Y` (when aliased) or the symbol name itself.
        const parts = spec.replace(/^type\s+/, '').split(/\s+as\s+/);
        const id = (parts.length > 1 ? parts[1] : parts[0])?.trim();
        return isReferenced(id);
      });
    if (kept.length === 0) return null;
    return `${head} ${kept.join(', ')} ${tail.trim()}`;
  }

  /** Rewrite dev-app-relative paths to the examples app's layout. */
  const upPrefix = '../'.repeat(featureDepth);
  function rewritePaths(line) {
    if (!line) return line;
    // forms-only `../_fixtures/<file>` — keep the underscore-prefixed dir.
    if (/'(?:\.\.\/)+_fixtures\//.test(line)) {
      return line.replace(/'(?:\.\.\/)+_fixtures\/([^']+)'/, `'${upPrefix}_fixtures/$1'`);
    }
    // generic `../...fixtures[/...]` → '<depth>fixtures' (depth-aware).
    return line.replace(/'(?:\.\.\/)+([^']*fixtures(?:[^']*)?)'/, `'${upPrefix}fixtures'`);
  }

  const filteredModuleImports = (story.moduleImports ?? [])
    // Skip @angular/core lines — coreLine already emits the detected symbols.
    .filter((l) => !/from\s*['"]@angular\/core['"]/.test(l))
    .map(filterImportLine)
    .filter((l) => l !== null)
    .map(rewritePaths);

  // Collect identifiers already covered by the filtered moduleImports.
  const coveredIds = new Set();
  for (const line of filteredModuleImports) {
    for (const id of importedSymbols(line)) coveredIds.add(id);
  }

  // Resolve any referenced identifiers still missing via the public-api map.
  // Walk both section.imports/hostDirectives (explicit) AND identifiers
  // word-matched in the comment-stripped setup (type annotations like
  // `filterRef: CngxFilter` that aren't in section.imports).
  const candidates = new Set([
    ...(section.imports ?? []),
    ...(story.hostDirectives ?? []),
  ]);
  for (const m of setup.matchAll(/\b([A-Z][A-Za-z0-9_]*)\b/g)) {
    candidates.add(m[1]);
  }

  const extraByPkg = new Map();
  for (const id of candidates) {
    if (coveredIds.has(id)) continue;
    const pkg = importMap.get(id);
    if (!pkg) continue;
    if (!extraByPkg.has(pkg)) extraByPkg.set(pkg, new Set());
    extraByPkg.get(pkg).add(id);
  }
  const extraLines = [...extraByPkg.entries()].map(
    ([pkg, ids]) => `import { ${[...ids].sort().join(', ')} } from '${pkg}';`,
  );

  return { lines: [coreLine, ...filteredModuleImports, ...extraLines] };
}

/** Escape a string for use as a TypeScript single-quoted literal. */
function tsQuote(s) {
  return "'" + String(s).replaceAll('\\', '\\\\').replaceAll("'", "\\'") + "'";
}

/** Remove TS line and block comments so a class name buried in a comment doesn't count as a reference. */
function stripCommentsForScan(s) {
  return String(s ?? '')
    .replace(/\/\*[\s\S]*?\*\//g, '')
    .replace(/\/\/[^\n]*/g, '');
}

/** Escape a string for embedding inside a TypeScript backtick template literal. */
function backtickEscape(s) {
  return String(s)
    .replaceAll('\\', '\\\\')
    .replaceAll('`', '\\`')
    .replaceAll('${', '\\${');
}

/**
 * Strip `<div class="event-grid">…</div>` debug-instrumentation blocks from
 * a template string. The live rendered demo keeps them (so consumers can see
 * directive state), but the displayed source should focus on directive usage,
 * not state-readout boilerplate. Walks balanced <div>/</div> tags so nested
 * event-row divs inside event-grid are removed together.
 */
function stripEventGrid(html) {
  const opener = /<div\b[^>]*\bclass=["'][^"']*\bevent-grid\b[^"']*["'][^>]*>/g;
  let result = html;
  while (true) {
    opener.lastIndex = 0;
    const m = opener.exec(result);
    if (!m) break;
    const start = m.index;
    let depth = 0;
    let i = start;
    let end = -1;
    while (i < result.length) {
      const lt = result.indexOf('<', i);
      if (lt === -1) break;
      const rest = result.slice(lt);
      if (/^<div\b/.test(rest)) {
        depth++;
        i = lt + 4;
      } else if (/^<\/div>/.test(rest)) {
        depth--;
        if (depth === 0) {
          end = lt + 6;
          break;
        }
        i = lt + 6;
      } else {
        i = lt + 1;
      }
    }
    if (end === -1) break;
    const before = result.slice(0, start).replace(/[ \t]*\n?[ \t]*$/, '\n');
    const after = result.slice(end).replace(/^[ \t]*\n?/, '');
    result = before + after;
  }
  return result;
}

/**
 * Strip the common leading whitespace shared by every non-empty line.
 * Story `setup` and `template` blocks live inside indented backtick literals
 * and arrive with an extra level of indentation that breaks the source view.
 */
function dedent(s) {
  const text = String(s).replace(/^\n+|\s+$/g, '');
  const lines = text.split('\n');
  const indents = lines
    .filter((l) => l.trim().length > 0)
    .map((l) => /^( *)/.exec(l)[1].length);
  if (indents.length === 0) return text;
  const min = Math.min(...indents);
  if (min === 0) return text;
  const pad = ' '.repeat(min);
  return lines.map((l) => (l.startsWith(pad) ? l.slice(min) : l)).join('\n');
}

/**
 * Escape bare custom-element tags (`<cngx-chart>`, `<my-foo>`) so Angular's
 * innerHTML sanitizer doesn't strip them silently. Known formatting tags
 * (`<code>`, `<strong>`, `<em>`, `<p>`, `<br>`) pass through unchanged.
 */
const SAFE_HTML_TAGS = new Set([
  'a', 'b', 'br', 'code', 'em', 'i', 'kbd', 'mark', 'p', 'pre',
  'span', 'strong', 'sup', 'sub', 'u', 'ul', 'ol', 'li',
]);
function escapeCustomElementTags(html) {
  return String(html).replace(/<\/?([a-zA-Z][a-zA-Z0-9-]*)\b[^>]*>/g, (match, tag) => {
    return SAFE_HTML_TAGS.has(tag.toLowerCase()) ? match : match.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  });
}

function emitComponentSource(meta, story, section, importMap) {
  const { lines } = buildImports(story, section, importMap, meta.featureDepth);
  const setup = [story.setup ?? '', section.setup ?? '']
    .map((b) => (b ?? '').trim())
    .filter(Boolean)
    .join('\n\n');

  // Component-decorator imports — pass section.imports through verbatim.
  // Selector→class mapping isn't reliable enough to filter safely
  // (e.g. CngxSkeletonContainer drives the <cngx-skeleton> element), so
  // any NG8113 'unused import' warnings are accepted as cosmetic noise.
  const tplImports = section.imports ?? [];
  const decoratorImports = tplImports.length > 0 ? `\n  imports: [${tplImports.join(', ')}],` : '';

  // Indent setup body two spaces (it's class-body code)
  const setupBody = setup
    .split('\n')
    .map((l) => (l.trim() ? '  ' + l : ''))
    .join('\n');

  // Intro header: story title + description, then per-section title + subtitle.
  // description/overview/subtitle may contain HTML — render via [innerHTML]
  // bound to class properties so the template parser doesn't choke.
  const introFields = [
    `  protected readonly _exTitle: string = ${tsQuote(story.title ?? '')};`,
    `  protected readonly _exDescription: string = ${tsQuote(escapeCustomElementTags(story.description ?? ''))};`,
    `  protected readonly _exSectionTitle: string = ${tsQuote(section.title ?? '')};`,
    `  protected readonly _exSubtitle: string = ${tsQuote(escapeCustomElementTags(section.subtitle ?? ''))};`,
  ].join('\n');

  // Source snippets shown in collapsible <details> blocks so consumers can
  // see what to write in their own code without leaving the iframe.
  const sourceImports = lines
    .filter((l) => !l.includes("from '@angular/core'"))
    .join('\n')
    .trim();
  // Dedent the raw setup blocks (NOT the .trim()-ed `setup` variable used
  // for the class body) so the first line still carries its full leading
  // indent and the dedent algorithm can see the true common prefix.
  const rawSetupBlocks = [story.setup ?? '', section.setup ?? '']
    .filter((b) => b && b.trim().length > 0)
    .join('\n\n');
  const dedentedSetup = dedent(rawSetupBlocks);
  const sourceTs = [sourceImports, dedentedSetup].filter(Boolean).join('\n\n').trim();
  const sourceHtml = dedent(stripEventGrid(section.template));
  const sourceFields = [
    `  protected readonly _exTs: string = \`${backtickEscape(sourceTs)}\`;`,
    `  protected readonly _exHtml: string = \`${backtickEscape(sourceHtml)}\`;`,
  ].join('\n');

  const intro = [
    `    <header class="cngx-ex-intro">`,
    `      @if (_exTitle) { <h1>{{ _exTitle }}</h1> }`,
    `      @if (_exDescription) { <p [innerHTML]="_exDescription"></p> }`,
    `      @if (_exSectionTitle && _exSectionTitle !== _exTitle) { <h2>{{ _exSectionTitle }}</h2> }`,
    `      @if (_exSubtitle) { <p class="cngx-ex-hint" [innerHTML]="_exSubtitle"></p> }`,
    `    </header>`,
  ].join('\n');

  const sourceBlocks = [
    `    <details class="cngx-ex-code">`,
    `      <summary>TypeScript</summary>`,
    `      <pre><code>{{ _exTs }}</code></pre>`,
    `    </details>`,
    `    <details class="cngx-ex-code">`,
    `      <summary>Template</summary>`,
    `      <pre><code>{{ _exHtml }}</code></pre>`,
    `    </details>`,
  ].join('\n');

  // Escape backticks and ${...} interpolations in the live template so
  // the surrounding TS template literal stays valid when stories embed
  // code snippets inside <pre><code> blocks.
  const template = section.template.trim().replaceAll('`', '\\`').replaceAll('${', '\\${');

  return `${GEN_HEADER}
// Source: dev-app/src/app/demos/${meta.demoFolder}/${meta.storyFileName}#section[${meta.sectionIndex}] "${section.title}"

${lines.join('\n')}

@Component({
  selector: 'app-${meta.demoSlug}-${meta.sectionSlug}',
  changeDetection: ChangeDetectionStrategy.OnPush,${decoratorImports}
  template: \`
${intro}
${indent(template, 4)}
${sourceBlocks}
  \`,
})
export class ${meta.className} {
${introFields}
${sourceFields}${setupBody ? '\n' + setupBody : ''}
}
`;
}

function indent(s, n) {
  const pad = ' '.repeat(n);
  return s.split('\n').map((l) => (l.length ? pad + l : l)).join('\n');
}

function emitRoutesSource(routes) {
  const sorted = [...routes].sort((a, b) => a.path.localeCompare(b.path));
  const entries = sorted.map((r) => [
    `  {`,
    `    path: '${r.path}',`,
    `    loadComponent: () => import('${r.importPath}').then((m) => m.${r.className}),`,
    `    data: { lib: '${r.lib}', category: '${r.category}', demo: ${JSON.stringify(r.demoTitle)}, section: ${JSON.stringify(r.sectionTitle)} },`,
    `  },`,
  ].join('\n')).join('\n');

  return `${GEN_HEADER}
import type { Routes } from '@angular/router';

export const routes: Routes = [
${entries}
  {
    path: '',
    loadComponent: () => import('./home/home.component').then((m) => m.HomeComponent),
  },
  { path: '**', redirectTo: '' },
];
`;
}

function emitRoutesMetaSource(routes) {
  const sorted = [...routes].sort((a, b) =>
    (a.lib + a.category + a.demoTitle + a.sectionTitle).localeCompare(
      b.lib + b.category + b.demoTitle + b.sectionTitle,
    ),
  );
  const entries = sorted.map((r) => `  ${JSON.stringify({
    path: r.path,
    lib: r.lib,
    category: r.category,
    demoSlug: r.demoSlug,
    sectionSlug: r.sectionSlug,
    flatDemo: r.flatDemo,
    demo: r.demoTitle,
    section: r.sectionTitle,
    apiComponents: r.apiComponents,
  })},`).join('\n');
  return `${GEN_HEADER}
export interface RouteMeta {
  path: string;
  lib: string;
  category: string;
  demoSlug: string;
  sectionSlug: string;
  flatDemo: boolean;
  demo: string;
  section: string;
  apiComponents: string[];
}

export const ROUTES_META: readonly RouteMeta[] = [
${entries}
];
`;
}

/**
 * Wipe and recreate the features/ root before generation. The new path
 * layout (features/<lib>/<sub>/<demo>/) makes per-demo pruning more error
 * prone than just starting fresh each run.
 */
async function resetFeaturesDir() {
  await rm(FEATURES_DIR, { recursive: true, force: true });
  await mkdir(FEATURES_DIR, { recursive: true });
}

async function main() {
  const manifestRaw = await readFile(MANIFEST, 'utf8');
  const manifest = JSON.parse(manifestRaw);
  if (!Array.isArray(manifest.approved)) {
    throw new Error('manifest.approved must be an array of demo folder paths relative to dev-app/src/app/demos/');
  }

  await resetFeaturesDir();

  const importMap = await buildPublicApiImportMap();

  const routes = [];

  for (const rel of manifest.approved) {
    const demoFolder = rel; // e.g. 'common/a11y/active-descendant-demo'
    const demoDir = join(DEMOS_ROOT, demoFolder);
    const files = await readdir(demoDir);
    const storyFiles = files.filter((f) => f.endsWith('.story.ts'));
    if (storyFiles.length === 0) {
      console.warn(`No story in ${demoFolder} — skipping`);
      continue;
    }

    // Use primary story (matches folder name minus -demo). Multi-story dirs aren't expected in SIMPLE.
    const folderLeaf = demoFolder.split('/').pop();
    const primary = storyFiles.find((f) => f === `${folderLeaf}.story.ts`) ?? storyFiles[0];
    const storyPath = join(demoDir, primary);
    const story = await loadStory(storyPath);

    const demoSlug = folderLeaf.replace(/-demo$/, '');
    const parts = demoFolder.split('/');
    const lib = parts[0];

    // Derive the lib sub-entry (category) for demos whose dev-app path is
    // flat: scan moduleImports + apiComponents for `@cngx/<lib>/<sub>` and
    // pick the dominant sub-entry. For paths that already have a category
    // segment (common/a11y/*, ui/feedback/*), keep it.
    const derivedCategory = parts.length === 3
      ? parts[1]
      : (() => {
          const counts = new Map();
          for (const line of story.moduleImports ?? []) {
            const m = line.match(new RegExp(`from\\s+['"]@cngx/${lib}/([\\w-]+)['"]`));
            if (m) counts.set(m[1], (counts.get(m[1]) ?? 0) + 1);
          }
          for (const sym of story.apiComponents ?? []) {
            const pkg = importMap.get(sym);
            if (!pkg) continue;
            const m = pkg.match(new RegExp(`^@cngx/${lib}/([\\w-]+)$`));
            if (m) counts.set(m[1], (counts.get(m[1]) ?? 0) + 1);
          }
          if (counts.size === 0) return '';
          return [...counts.entries()].sort((a, b) => b[1] - a[1])[0][0];
        })();

    // Collapse a redundant `category/category-demo` nesting (common/card/card-demo,
    // forms/select-demo with derived category=select, …).
    const isFlatDemo = derivedCategory !== '' && derivedCategory === demoSlug;
    // Feature dir mirrors the cngx library structure:
    //   common/a11y/active-descendant-demo → features/common/a11y/active-descendant/
    //   common/card/card-demo              → features/common/card/        (flat)
    //   forms/action-select-demo           → features/forms/select/action-select/
    //   forms/select-demo                  → features/forms/select/       (flat)
    //   forms/autosize-demo                → features/forms/input/autosize/
    //   data-display/treetable-demo        → features/data-display/treetable/
    const pathSegments = isFlatDemo
      ? [lib, derivedCategory]
      : derivedCategory !== ''
        ? [lib, derivedCategory, demoSlug]
        : [lib, demoSlug];
    const demoPath = pathSegments.join('/');
    const featureDir = join(FEATURES_DIR, ...pathSegments);
    const featureImportPath = './features/' + demoPath;

    // Copy any co-located helper files referenced by `from './<file>'` in
    // moduleImports — e.g. toast-demo imports './sample-toast-body'.
    const helperFiles = new Set();
    for (const line of story.moduleImports ?? []) {
      const m = line.match(/from\s+['"](\.\/[^'"]+)['"]/);
      if (m) helperFiles.add(m[1]);
    }
    await mkdir(featureDir, { recursive: true });

    for (const rel of helperFiles) {
      // Try resolving with and without `.ts` extension.
      const candidates = [
        join(demoDir, rel + '.ts'),
        join(demoDir, rel),
      ];
      for (const candidate of candidates) {
        try {
          const content = await readFile(candidate, 'utf8');
          const destName = rel.replace(/^\.\//, '') + (candidate.endsWith('.ts') ? '.ts' : '');
          await writeFile(join(featureDir, destName), content);
          break;
        } catch {
          /* try next */
        }
      }
    }

    const category = derivedCategory;

    const sections = story.sections ?? [];
    for (let i = 0; i < sections.length; i++) {
      const section = sections[i];
      const cleanedTitle = cleanSectionTitle(section.title);
      let sectionSlug = slugify(cleanedTitle);
      // If cleaning produced an empty slug (e.g. title was only the prefix),
      // fall back to a numbered slug to keep routes unique.
      if (!sectionSlug) sectionSlug = `section-${i + 1}`;
      const className = kebabToPascal(demoSlug) + kebabToPascal(sectionSlug);

      const code = emitComponentSource(
        {
          demoFolder,
          storyFileName: primary,
          sectionIndex: i,
          demoSlug,
          sectionSlug,
          className,
          // +1 to account for the `features/` dir itself; the section file
          // lives at `features/<...pathSegments>/<section>.ts`, so it needs
          // pathSegments.length + 1 `..` hops to reach examples/src/app/.
          featureDepth: pathSegments.length + 1,
        },
        story,
        section,
        importMap,
      );
      await writeFile(join(featureDir, `${sectionSlug}.component.ts`), code);

      routes.push({
        path: `${demoPath}/${sectionSlug}`,
        importPath: featureImportPath + '/' + sectionSlug + '.component',
        demoSlug,
        sectionSlug,
        className,
        lib,
        category,
        flatDemo: isFlatDemo,
        demoTitle: story.title,
        sectionTitle: section.title,
        apiComponents: story.apiComponents ?? [],
      });
    }
    console.log(`Generated ${sections.length} components for ${demoFolder}`);
  }

  await writeFile(join(EXAMPLES_APP, 'app.routes.ts'), emitRoutesSource(routes));
  await writeFile(join(EXAMPLES_APP, '_routes-meta.ts'), emitRoutesMetaSource(routes));
  console.log(`\nWrote ${routes.length} routes across ${manifest.approved.length} demos.`);
}

await main().catch((err) => {
  console.error(err);
  process.exit(1);
});
